import{_ as e,o as a,c as r,a2 as d}from"./chunks/framework.c3r8iWL8.js";const m=JSON.parse('{"title":"Guide: Automated Testing & QA","description":"Reference template for AI-native enterprise delivery on AWS","frontmatter":{},"headers":[],"relativePath":"guides/automated-testing-qa.md","filePath":"guides/automated-testing-qa.md","lastUpdated":1782929962000}'),n={name:"guides/automated-testing-qa.md"};function s(o,t,i,l,h,c){return a(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="guide-automated-testing-qa" tabindex="-1">Guide: Automated Testing &amp; QA <a class="header-anchor" href="#guide-automated-testing-qa" aria-label="Permalink to &quot;Guide: Automated Testing &amp; QA&quot;">​</a></h1><p><strong>Decision:</strong> What to automate, what stays human, and how AI fits the test pyramid.</p><p>Related: <a href="./../qa-guardrails.html">qa-guardrails.md</a> · <a href="./../sops/SOP-005-pr-review.html">SOP-005</a></p><hr><h2 id="clarifying-no-manual-qa" tabindex="-1">Clarifying &quot;no manual QA&quot; <a class="header-anchor" href="#clarifying-no-manual-qa" aria-label="Permalink to &quot;Clarifying &quot;no manual QA&quot;&quot;">​</a></h2><p>This model means <strong>no manual test execution</strong> in a QA phase. Humans still:</p><ul><li>Review test <strong>design</strong> in PRs</li><li>Accept staging behavior (PO demo + green synthetics)</li><li>Triage production alerts</li></ul><hr><h2 id="pyramid-layers-—-options" tabindex="-1">Pyramid layers — options <a class="header-anchor" href="#pyramid-layers-—-options" aria-label="Permalink to &quot;Pyramid layers — options&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Layer</th><th>Common tools</th><th>Automate?</th><th>Human role</th></tr></thead><tbody><tr><td>Unit</td><td>pytest, jest, go test</td><td>Yes</td><td>Review edge cases in PR</td></tr><tr><td>Contract</td><td>Schemathesis, Pact, Dredd</td><td>Yes</td><td>Approve spec changes</td></tr><tr><td>Integration</td><td>Testcontainers, LocalStack</td><td>Yes</td><td>Maintain fixture policy</td></tr><tr><td>E2E</td><td>Playwright, Cypress headless</td><td>Yes</td><td>Review flaky test fixes</td></tr><tr><td>Mutation</td><td>Stryker, mutmut</td><td>Yes (nightly/release)</td><td>Set tier thresholds</td></tr><tr><td>Property-based</td><td>Hypothesis, fast-check</td><td>Selective</td><td>Choose critical domains</td></tr><tr><td>Load</td><td>k6, Artillery</td><td>Pre-release / continuous</td><td>Define SLO targets</td></tr></tbody></table><hr><h2 id="ai-generated-tests" tabindex="-1">AI-generated tests <a class="header-anchor" href="#ai-generated-tests" aria-label="Permalink to &quot;AI-generated tests&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Approach</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>AI from OpenAPI</strong></td><td>Fast; aligned to contract</td><td>Misses domain invariants</td></tr><tr><td><strong>AI from code</strong></td><td>Matches current behavior</td><td><strong>Pitfall:</strong> locks in bugs</td></tr><tr><td><strong>AI maintenance on spec diff</strong></td><td>Keeps suite current</td><td>Needs human review of diffs</td></tr><tr><td><strong>AI from incident postmortem</strong></td><td>Closes prod gaps</td><td>One-off unless wired to SOP</td></tr></tbody></table><p><strong>Recommended:</strong> Generate from spec + ADR context; human approves in PR.</p><hr><h2 id="staging-validation-alternatives" tabindex="-1">Staging validation alternatives <a class="header-anchor" href="#staging-validation-alternatives" aria-label="Permalink to &quot;Staging validation alternatives&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Approach</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>PO demo + green metrics</strong></td><td>Fast; product-focused</td><td>Subjective without synthetics</td></tr><tr><td><strong>Synthetic canaries only</strong></td><td>Objective</td><td>May miss UX gaps</td></tr><tr><td><strong>Manual exploratory (timed)</strong></td><td>Finds odd paths</td><td>Doesn&#39;t scale; contradicts pure automation</td></tr></tbody></table><p><strong>Recommended:</strong> Synthetics + PO acceptance on staging for user-facing T1/T2 — not a manual regression script.</p><hr><h2 id="pitfalls" tabindex="-1">Pitfalls <a class="header-anchor" href="#pitfalls" aria-label="Permalink to &quot;Pitfalls&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pitfall</th><th>Why it hurts</th><th>Mitigation</th></tr></thead><tbody><tr><td><strong>E2E-only strategy</strong></td><td>Slow CI; flaky</td><td>Pyramid balance</td></tr><tr><td><strong>Flaky tests ignored</strong></td><td>Alert fatigue; real bugs missed</td><td>Quarantine + fix SLA</td></tr><tr><td><strong>100% line coverage obsession</strong></td><td>False confidence</td><td>Mutation score on T1</td></tr><tr><td><strong>AI tests never reviewed</strong></td><td>Nonsense assertions merge</td><td>Reviewer checklist</td></tr><tr><td><strong>No contract tests</strong></td><td>Spec drift undetected</td><td>Schemathesis in CI</td></tr><tr><td><strong>Skipping integration tests</strong></td><td>&quot;Works on my machine&quot;</td><td>Ephemeral env or Testcontainers</td></tr><tr><td><strong>Manual regression before release</strong></td><td>Bottleneck; unreproducible</td><td>Automate path or drop it</td></tr><tr><td><strong>Tier 1 without mutation gate</strong></td><td>Weak tests pass</td><td>Tier-based CI policy</td></tr></tbody></table><hr><h2 id="recommended-starting-point" tabindex="-1">Recommended starting point <a class="header-anchor" href="#recommended-starting-point" aria-label="Permalink to &quot;Recommended starting point&quot;">​</a></h2><p>Unit + contract on every PR → integration for DB/queue paths → E2E for critical journeys → mutation nightly for T1 → AI generates from OpenAPI with human PR review.</p><hr><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./spec-driven-development.html">Spec-driven development</a> · <a href="./static-analysis-linting.html">Linters &amp; static analysis</a> · <a href="./ci-cd-release.html">CI/CD</a> · <a href="./observability-monitoring-qa.html">Observability</a></li></ul>',27)])])}const u=e(n,[["render",s]]);export{m as __pageData,u as default};
